import React, { useState, useEffect } from 'react';
import { api } from '../services/api'; 
import { useAuth } from '../context/AuthContext';
import { Package, MapPin, CheckCircle, Truck, Loader2, Bike, Store, XCircle } from 'lucide-react';

const MisPedidosCliente = ({ userCoords }) => {
  const [pedidos, setPedidos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [progresoEnvio, setProgresoEnvio] = useState({}); 
  const { user } = useAuth();

  const fetchPedidos = async () => {
    try {
      const clienteId = user?.id || user?._id;
      if (!clienteId) return;
      const data = await api.getPedidosCliente(clienteId);
      setPedidos(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Error al obtener historial:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (user) fetchPedidos();
  }, [user]);

  useEffect(() => {
    pedidos.forEach(pedido => {
      if (pedido.estado?.toLowerCase() === 'camino' && !progresoEnvio[pedido._id]) {
        iniciarSimulacionRealista(pedido);
      }
    });
  }, [pedidos]);

  const iniciarSimulacionRealista = (pedido) => {
    let progreso = 0;
    const tiempoViajeBase = 30; 
    const interval = setInterval(() => {
      progreso += 1;
      setProgresoEnvio(prev => ({ ...prev, [pedido._id]: progreso }));
      if (progreso >= 100) clearInterval(interval);
    }, (tiempoViajeBase * 1000) / 100);
  };

  const handleCancelar = async (pedidoId) => {
    if (!window.confirm("¿Estás seguro de que deseas cancelar este pedido?")) return;
    try {
      await api.cancelarPedido(pedidoId);
      alert("Pedido cancelado correctamente.");
      fetchPedidos(); // Recargamos la lista
    } catch (err) {
      alert(err.message);
    }
  };

  if (loading) return <div style={msgContainer}><Loader2 size={40} className="animate-spin" color="#e67e22" /><p>Cargando pedidos...</p></div>;

  return (
    <div style={container}>
      <h2 style={title}>Mis Compras</h2>
      <div style={listContainer}>
        {pedidos.filter(p => p.estado !== 'cancelado').map((pedido) => {
          const p = progresoEnvio[pedido._id] || (pedido.estado === 'completado' ? 100 : 0);
          // REGLA: Solo cancelable si el progreso es bajo (está en el local) y no está en camino oficialmente
          const esCancelable = p < 15 && pedido.estado !== 'camino';

          return (
            <div key={pedido._id} style={orderCard}>
              <div style={orderHeader}>
                <span style={dateText}>#{pedido._id?.slice(-5)}</span>
                <div style={{display: 'flex', gap: '10px', alignItems: 'center'}}>
                    {esCancelable && (
                        <button onClick={() => handleCancelar(pedido._id)} style={cancelBtn}>
                            <XCircle size={14} /> Cancelar
                        </button>
                    )}
                    <span style={{...statusText, color: p === 100 ? '#22c55e' : '#3182ce'}}>
                        {p === 100 ? 'ENTREGADO' : pedido.estado?.toUpperCase()}
                    </span>
                </div>
              </div>

              {/* BARRA DE 3 SEPARACIONES */}
              <div style={stepperWrapper}>
                <div style={stepperBackground}><div style={{...stepperFill, width: `${p}%`}} /></div>
                <div style={nodesContainer}>
                  <div style={nodeGroup}>
                    <div style={{...node, backgroundColor: p >= 0 ? '#3182ce' : '#e2e8f0'}}><Store size={14} color="white" /></div>
                    <span style={nodeLabel}>Local</span>
                  </div>
                  <div style={nodeGroup}>
                    <div style={{...node, backgroundColor: p >= 50 ? '#3182ce' : '#e2e8f0'}}><Bike size={14} color="white" /></div>
                    <span style={nodeLabel}>Camino</span>
                  </div>
                  <div style={nodeGroup}>
                    <div style={{...node, backgroundColor: p >= 100 ? '#22c55e' : '#e2e8f0'}}><CheckCircle size={14} color="white" /></div>
                    <span style={nodeLabel}>¡Llegó!</span>
                  </div>
                </div>
                {p > 0 && p < 100 && (
                  <div style={{...truckFloat, left: `calc(${p}% - 15px)`}}><Truck size={18} color="#3182ce" /></div>
                )}
              </div>

              <div style={bodyCard}>
                <div style={localRow}>
                  <div style={avatarLocal}>{pedido.local?.nombre?.charAt(0)}</div>
                  <div>
                    <h4 style={localName}>{pedido.local?.nombre}</h4>
                    <p style={localAddr}><MapPin size={12} /> {pedido.local?.direccion}</p>
                  </div>
                </div>

                <div style={itemsBox}>
                  {pedido.items?.map((item, i) => (
                    <div key={i} style={itemLine}>
                      <span>{item.cantidad}x {item.producto}</span>
                      <span>${item.precio * item.cantidad}</span>
                    </div>
                  ))}
                </div>

                <div style={priceFooter}>
                  <div style={priceRow}><span>Envío</span><span>${pedido.costoEnvio || 800}</span></div>
                  <div style={totalRow}><span>Total</span><span>${pedido.total}</span></div>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

